    toc: [ { id: "overview", title: "overview", level: 2 }, { id: "p2p-crypto-payments-overview", title: "P2P Crypto Payments Overview", level: 2 }, { id: "wallets", title: "wallets", level: 2 }, { id: "best-p2p-crypto-wallets", title: "Best P2P Crypto Wallets", level: 2 }, { id: "lightning", title: "lightning", level: 2 }, { id: "lightning-network-for-p2p", title: "Lightning Network for P2P", level: 2 }, { id: "stablecoins", title: "stablecoins", level: 2 }, { id: "stablecoin-p2p-transfers", title: "Stablecoin P2P Transfers", level: 2 }, { id: "tips", title: "tips", level: 2 }, { id: "best-practices", title: "Best Practices", level: 2 } ],
    faqs: [ { question: "What is the cheapest way to send crypto to someone?", answer: "Stablecoins on low-fee networks like Solana, Tron, or Polygon cost fractions of a cent to transfer. Bitcoin Lightning payments are also nearly free and instant." }, { question: "Can I use Venmo or Cash App for crypto P2P payments?", answer: "Cash App supports Bitcoin purchases and Lightning payments to external wallets. Venmo allows buying and selling crypto but currently limits transfers to other Venmo users. Neither supports full external crypto transfers for all assets." }, { question: "Is it safe to send crypto to another person?", answer: "Crypto P2P transfers are secure and irreversible once confirmed. Always verify the recipient address carefully, start with a small test amount for first-time transfers, and use QR codes to avoid typing errors." }, ],
